uint16_t adj_matrix_to_mask_small_N(int N_nodes, const bool adj_matrix[][N_MAX_GED_CAP], const std::vector<int>& p_perm) {
    uint16_t mask = 0;
    int bit_idx = 0;
    for (int i = 0; i < N_nodes; ++i) {
        for (int j = i + 1; j < N_nodes; ++j) {
            if (adj_matrix[p_perm[i]][p_perm[j]]) {
