            std::cout << best_g_idx << std::endl;

        } else {
            // Threshold graph decoding using sorted degree sequence MLE
            // Compute degree sequence of H_k
            std::vector<int> degrees(N_ACTUAL, 0);
            int char_idx = 0;
            for (int i = 0; i < N_ACTUAL; ++i) {
                for (int j = i + 1; j < N_ACTUAL; ++j) {
                    if (char_idx < (int)h_str.length() && h_str[char_idx] == '1') {
