                        degrees[j]++;
                    }
                    char_idx++;
                }
            }

            // Sort degrees in ascending order
            std::sort(degrees.begin(), degrees.end());

            // For each candidate graph j, compute MLE score (sum of squared residuals)
            int best_j = 0;
            double best_score = 1e18;

            for (int j = 0; j < M_graphs; ++j) {
                int h = hub_counts[j]; // number of hubs in graph j
                // Expected degrees after noise:
                // Hub vertex (original degree N-1): mean = (N-1)*(1-eps)
                // Non-hub vertex (original degree h): mean = h*(1-2*eps) + (N-1)*eps
