// For threshold graphs: edge count of graph with h hubs = h*(2N - h - 1)/2
// These are all distinct for h in [0, N-1]. Spacing in edge count between adjacent h:
//   E(h+1) - E(h) = N - h - 1
// After noise: expected edge count = E_orig * (1-2*eps) + L*eps
// Noise std on total edge count: sqrt(L * eps * (1-eps))
// Spacing of expected edge counts: (N-h-1) * (1-2*eps)
// Minimum spacing (worst case, h near N-1): ~1*(1-2*eps) is too small
// So we should spread hub counts to maintain good spacing.

// Strategy: try each candidate N, compute expected error rate, pick N that maximizes 0.9^E / N
double best_expected_score = -1;
int best_N = 4;
Strategy best_strategy = Strategy::GED;

// First evaluate GED strategy
{
    int N_ged = N_for_GED_strat;
    int L_ged = N_ged * (N_ged - 1) / 2;
    // For GED with well-separated graphs, error rate depends on min_ged vs noise
    // Expected noise per graph: L_ged * eps edges are flipped
    // If min_ged between chosen graphs is d, then error happens when noise > d/2
    // This is hard to compute exactly, but GED with N=6 works great for eps < 0.2
    // Approximate: Prob(error) ~ prob that Hamming dist to wrong graph < dist to correct
    // For small eps: very good. For large eps: degrades.
    // Use a rough estimate based on the observation that with 156 graphs at N=6,
    // min GED is about 3-4 for M<=100.
    double p_correct_ged;
    if (eps < 0.01) p_correct_ged = 1.0;
    else if (eps <= 0.10) p_correct_ged = 0.99;
    else if (eps <= 0.20) p_correct_ged = 0.95;
    else if (eps <= 0.30) p_correct_ged = 0.80;
    else p_correct_ged = 0.60;

    double E_ged = 100.0 * (1.0 - p_correct_ged);
    double score_ged = std::pow(0.9, E_ged) / N_ged;
    best_expected_score = score_ged;
    best_N = N_ged;
    best_strategy = Strategy::GED;
}

// Evaluate threshold graph strategy for various N
for (int N_try = std::max(4, M_graphs + 1); N_try <= 100; ++N_try) {
    int L_try = N_try * (N_try - 1) / 2;
    // Spread M hub counts evenly in [0, N_try-1]
    // Minimum spacing between adjacent hub counts: floor((N_try-1) / (M-1))
    double spacing = (M_graphs > 1) ? (double)(N_try - 1) / (M_graphs - 1) : (double)N_try;

    // Minimum edge count difference between adjacent graphs:
    // For hub count h, edges = h*(2*N_try - h - 1)/2
    // Diff = (N_try - h - 1) for step of 1 in h. With spacing s: diff ~ s * (N_try - h_avg - 1)
    // Worst case: h near N/2, diff per unit h = N_try/2 - 1. Spacing s hub counts apart: s*(N/2)
    // Actually more precisely: edges(h) = h*N_try - h*(h+1)/2
    // edges(h+s) - edges(h) = s*N_try - s*(2h+s+1)/2 = s*(N_try - h - (s+1)/2)
    // Minimum is at max h. With hub_max ~ N-1, diff_min ~ spacing * (N - hub_max - 1) ... approaches 0
    // Better to think about it as: with evenly spaced hub counts, the edge count differences
    // The middle hub counts give the best separation.

    // Expected edge count noise: each of L_try bits flips with prob eps.
    // Total edge count follows Binomial, after flip:
    // For graph with E_orig edges: E_observed ~ Binomial(E_orig, 1-eps) + Binomial(L-E_orig, eps)
    // Mean = E_orig*(1-2*eps) + L*eps, Var = L*eps*(1-eps)
    double noise_std = std::sqrt(L_try * eps * (1.0 - eps));

    // Expected edge counts form a sequence. The spacing between adjacent expected values:
    // E_orig(k) = h_k * (2*N_try - h_k - 1) / 2 where h_k = round(k * (N_try-1) / (M-1))
    // After noise transform: expected_k = E_orig(k) * (1-2*eps) + L*eps
    // Spacing: (E_orig(k+1) - E_orig(k)) * (1-2*eps)
    // E_orig difference for hub count step of s: approximately s * (N_try - N_try/2) = s*N_try/2 (average)
    // More precisely: average spacing in edge count = (E_orig(M-1) - E_orig(0)) / (M-1) * (1-2*eps)
    // E_orig(0) = 0, E_orig(M-1) = hub_max * (2*N_try - hub_max - 1) / 2 where hub_max ~ N_try - 1
    // = (N_try-1)*N_try/2 = L_try
    // So average spacing in expected edge count = L_try * (1-2*eps) / (M-1)
    double avg_spacing = L_try * std::max(0.01, 1.0 - 2.0 * eps) / std::max(1, M_graphs - 1);

    // With Gaussian approximation, P(error) ~ 2 * Phi(-spacing/(2*noise_std))
    // For our multi-class problem: P(correct) ~ 1 - 2*Phi(-avg_spacing/(2*noise_std))
    double snr = avg_spacing / (2.0 * noise_std);
    // Phi(-x) ~ erfc(x/sqrt(2))/2
    double p_correct;
    if (snr > 4.0) p_correct = 1.0;
    else if (snr < 0.1) p_correct = 1.0 / M_graphs;
    else {
        // Use erfc approximation
        p_correct = 1.0 - std::erfc(snr / std::sqrt(2.0));
        p_correct = std::max(p_correct, 1.0 / M_graphs);
    }

    double E_threshold = 100.0 * (1.0 - p_correct);
    double score_threshold = std::pow(0.9, E_threshold) / N_try;

    if (score_threshold > best_expected_score) {
        best_expected_score = score_threshold;
        best_N = N_try;
        best_strategy = Strategy::THRESHOLD_GRAPH;
    }
}

