} else {
    // Threshold graph decoding using log-likelihood
    // For each candidate graph j with h hubs, compute the log-likelihood
    // that the observed H could have come from G_j after noise + permutation.
    //
    // Key insight: After vertex shuffle, we don't know which vertices are hubs.
    // But we can compute the likelihood marginalized over the vertex assignment.
    // Approximation: sort observed degrees, assign top-h to hubs, bottom to non-hubs.
    // Then compute per-edge log-likelihood.

    // Parse H into adjacency
    string_to_adj_matrix_query(h_str, N_ACTUAL);

    // Compute degrees
    std::vector<int> degrees(N_ACTUAL, 0);
    for (int i = 0; i < N_ACTUAL; ++i)
        for (int j = i + 1; j < N_ACTUAL; ++j)
            if (CURRENT_GRAPH_ADJ_QUERY[i][j])
                degrees[i]++, degrees[j]++;

    // Get sorted vertex indices by degree (descending)
    std::vector<int> order(N_ACTUAL);
    std::iota(order.begin(), order.end(), 0);
    std::sort(order.begin(), order.end(), [&](int a, int b) {
        return degrees[a] > degrees[b];
    });

    double log_p_edge = std::log(1.0 - eps);
    double log_p_noedge = std::log(eps);
    double log_p_flip = std::log(eps);
    double log_p_noflip = std::log(1.0 - eps);

    int best_j = 0;
    double best_ll = -1e18;

    for (int j = 0; j < M_graphs; ++j) {
        int h = hub_counts[j];

        // Assign top-h vertices as hubs
        std::vector<bool> is_hub(N_ACTUAL, false);
        for (int i = 0; i < h; ++i)
            is_hub[order[i]] = true;

        // Compute log-likelihood: for each edge (i,j) in H,
        // if original had edge: P(observed=1) = 1-eps
        // if original had no edge: P(observed=1) = eps
        double ll = 0.0;
        for (int i = 0; i < N_ACTUAL; ++i) {
            for (int jj = i + 1; jj < N_ACTUAL; ++jj) {
                bool orig_edge = (is_hub[i] || is_hub[jj]);
                bool obs_edge = CURRENT_GRAPH_ADJ_QUERY[i][jj];

                if (orig_edge) {
                    ll += obs_edge ? log_p_noflip : log_p_flip;
                } else {
                    ll += obs_edge ? log_p_flip : log_p_noflip;
                }
            }
        }

        if (ll > best_ll) {
            best_ll = ll;
            best_j = j;
        }
    }

    std::cout << best_j << std::endl;
}

