    else if (target_p > 0.001) snr_required = 3.09;
    else if (target_p > 0.0001) snr_required = 3.72;
    else snr_required = 4.26;

    // SNR = sqrt(N)*(1-2*eps) / (2*sqrt(eps*(1-eps)))
    // N = (snr_required * 2 * sqrt(eps*(1-eps)) / (1-2*eps))^2
