        for (int k = 0; k < M_graphs; ++k) {
            uint16_t mask_to_print = 0;
            if (k < (int)chosen_mask_indices_greedy.size() &&
                !available_canonical_masks.empty() &&
                chosen_mask_indices_greedy[k] < (int)available_canonical_masks.size()) {
                mask_to_print = available_canonical_masks[chosen_mask_indices_greedy[k]];
            }

            bool temp_adj[N_MAX_GED_CAP][N_MAX_GED_CAP];
            mask_to_adj_matrix_small_N(mask_to_print, N_ACTUAL, temp_adj);
            for (int r = 0; r < N_ACTUAL; ++r)
                for (int c = 0; c < N_ACTUAL; ++c)
                    G_ADJS_CHOSEN_GED[k][r][c] = temp_adj[r][c];

            std::string s_out = "";
            for (int bit_idx = 0; bit_idx < L_ACTUAL; ++bit_idx) {
                s_out += ((mask_to_print >> bit_idx) & 1) ? '1' : '0';
            }
            std::cout << s_out << std::endl;
        }

    } else {
        // Threshold graph approach with adaptive N
        hub_counts.resize(M_graphs);
        if (M_graphs == 1) {
            hub_counts[0] = 0;
        } else {
            for (int k = 0; k < M_graphs; ++k) {
                hub_counts[k] = (int)std::round((double)k * (N_ACTUAL - 1) / (M_graphs - 1));
            }
            for (int k = 1; k < M_graphs; ++k) {
                if (hub_counts[k] <= hub_counts[k - 1]) {
                    hub_counts[k] = hub_counts[k - 1] + 1;
                }
            }
            if (hub_counts[M_graphs - 1] >= N_ACTUAL) {
                int excess = hub_counts[M_graphs - 1] - (N_ACTUAL - 1);
                for (int k = 0; k < M_graphs; ++k) {
                    hub_counts[k] = std::max(0, hub_counts[k] - excess);
                }
                for (int k = 1; k < M_graphs; ++k) {
                    if (hub_counts[k] <= hub_counts[k - 1]) {
                        hub_counts[k] = hub_counts[k - 1] + 1;
                    }
                }
            }
            for (int k = 0; k < M_graphs; ++k) {
                hub_counts[k] = std::min(N_ACTUAL - 1, std::max(0, hub_counts[k]));
            }
        }

        for (int k = 0; k < M_graphs; ++k) {
            std::cout << threshold_graph_to_string(N_ACTUAL, hub_counts[k]) << std::endl;
        }
    }
    std::cout.flush();

    // Query phase
    for (int q = 0; q < 100; ++q) {
        std::string h_str;
        std::cin >> h_str;

        if (current_strategy == Strategy::GED) {
            if (M_graphs == 0) { std::cout << 0 << std::endl; std::cout.flush(); continue; }
            string_to_adj_matrix_query(h_str, N_ACTUAL);

            int best_g_idx = 0;
            int min_dist_found = L_ACTUAL + 2;
            for (int j = 0; j < M_graphs; ++j) {
                if (j >= (int)G_ADJS_CHOSEN_GED.size()) continue;
                int dist = min_edit_distance_global_perm_small_N(G_ADJS_CHOSEN_GED[j]);
                if (dist < min_dist_found) {
                    min_dist_found = dist;
                    best_g_idx = j;
                }
            }
            std::cout << best_g_idx << std::endl;

        } else {
            // Threshold graph decoding using log-likelihood with degree-based assignment
            string_to_adj_matrix_query(h_str, N_ACTUAL);

            std::vector<int> degrees(N_ACTUAL, 0);
            for (int i = 0; i < N_ACTUAL; ++i)
                for (int j = i + 1; j < N_ACTUAL; ++j)
                    if (CURRENT_GRAPH_ADJ_QUERY[i][j])
                        degrees[i]++, degrees[j]++;

            // Sort vertex indices by degree (descending)
            std::vector<int> order(N_ACTUAL);
            std::iota(order.begin(), order.end(), 0);
            std::sort(order.begin(), order.end(), [&](int a, int b) {
                return degrees[a] > degrees[b];
            });

            // Precompute cumulative edge counts for efficient LL computation
            // For threshold graph with h hubs (assigned as top-h by degree):
            // - edges among top-h (hub-hub pairs): should be present
            // - edges between top-h and bottom-(N-h) (hub-nonhub pairs): should be present
            // - edges among bottom-(N-h) (nonhub-nonhub pairs): should be absent
            //
            // LL = matches * log(1-eps) + mismatches * log(eps)
            // Maximizing LL = maximizing matches (since log(1-eps) > log(eps))
            //
            // matches(h) = edge_in_top_h + edge_between + (nonhub_pairs - edge_in_bottom)
            //            = total_edges - edge_in_bottom + nonhub_pairs - edge_in_bottom
            //            = total_edges + nonhub_pairs - 2*edge_in_bottom
            //            = total_edges + (N-h)*(N-h-1)/2 - 2*edge_in_bottom(h)
            //
            // where edge_in_bottom(h) = edges among vertices order[h..N-1]

            // Precompute edge_in_bottom for all h from 0 to N
            // edge_in_bottom(0) = total edges (all vertices are "bottom")
            // edge_in_bottom(h) = edge_in_bottom(h-1) - edges from order[h-1] to order[h..N-1]
            int total_edges = 0;
            for (int i = 0; i < N_ACTUAL; ++i)
                for (int j = i + 1; j < N_ACTUAL; ++j)
                    if (CURRENT_GRAPH_ADJ_QUERY[i][j])
                        total_edges++;

            std::vector<int> edge_in_bottom(N_ACTUAL + 1, 0);
            edge_in_bottom[0] = total_edges;
            for (int h = 1; h <= N_ACTUAL; ++h) {
                int v = order[h - 1]; // vertex being moved from bottom to top
                int edges_from_v_to_remaining_bottom = 0;
                for (int idx = h; idx < N_ACTUAL; ++idx) {
                    if (CURRENT_GRAPH_ADJ_QUERY[v][order[idx]])
                        edges_from_v_to_remaining_bottom++;
                }
                // Also subtract edges from v to previously-moved vertices (already in top)
                // Actually edge_in_bottom(h) = edges among {order[h], ..., order[N-1]}
                // edge_in_bottom(h) = edge_in_bottom(h-1) - (edges from order[h-1] to {order[h]..order[N-1]})
                //                    - (edges from order[h-1] to {order[0]..order[h-2]} that were counted)
                // Wait, edge_in_bottom(h-1) = edges among {order[h-1], order[h], ..., order[N-1]}
                // edge_in_bottom(h) = edges among {order[h], ..., order[N-1]}
                // Difference = edges from order[h-1] to {order[h], ..., order[N-1]}
                edge_in_bottom[h] = edge_in_bottom[h - 1] - edges_from_v_to_remaining_bottom;
            }

            double log_ratio = std::log((1.0 - eps) / eps);
            int best_j = 0;
            double best_matches = -1;

            for (int j = 0; j < M_graphs; ++j) {
                int h = hub_counts[j];
                int nonhub_pairs = (N_ACTUAL - h) * (N_ACTUAL - h - 1) / 2;
                double matches = (double)total_edges + nonhub_pairs - 2.0 * edge_in_bottom[h];

                if (matches > best_matches) {
                    best_matches = matches;
                    best_j = j;
                }
            }

            std::cout << best_j << std::endl;
        }
        std::cout.flush();
    }

    return 0;
}
