if (eps <= 0.20) {
    current_strategy = Strategy::GED;
    N_ACTUAL = N_for_GED_strat;
} else {
    current_strategy = Strategy::THRESHOLD_GRAPH;
    // Search for optimal N that maximizes expected 0.9^E / N.
    // Detection accuracy depends on log-likelihood gap between adjacent codewords.
    // For threshold graph: the LL gap comes from the matches formula.
    // Two adjacent hub counts h and h+s: the matches difference is approximately
    // s * (N - 2*h - s) * (1 - 2*eps) (from the edge count difference scaled by noise)
    // The noise in matches ~ sqrt(L * eps * (1-eps)) (since each edge independently flips)
    // With spacing s = (N-1)/(M-1), minimum s at h=N/2:
    //   delta_matches ≈ s * N/2 * (1-2*eps) = (N-1)/(M-1) * N/2 * (1-2*eps)
    //   noise_std ≈ sqrt(N*(N-1)/2 * eps*(1-eps))
    //   SNR = delta / noise = [(N-1)*N*(1-2*eps)] / [(M-1) * 2 * sqrt(N*(N-1)/2*eps*(1-eps))]
    //       = [sqrt(N*(N-1)/2) * (1-2*eps)] / (M-1)  * sqrt(1/(eps*(1-eps)))
    //       ≈ sqrt(N/2) * (1-2*eps) / ((M-1) * sqrt(eps*(1-eps)))
    // P(error per query) ≈ erfc(SNR/sqrt(2)) (Gaussian approx)
    // Want to maximize: 0.9^(100*P_err) / N
    // Take log: 100*P_err*ln(0.9) - ln(N) = -10.536*P_err - ln(N)
    // Minimize: 10.536*P_err + ln(N)

    double best_obj = 1e18;
    int best_N_try = 100;
    for (int N_try = std::max(4, M_graphs); N_try <= 100; ++N_try) {
        double L_try = N_try * (N_try - 1) / 2.0;
        double spacing = (N_try - 1.0) / std::max(1, M_graphs - 1);
        // Minimum delta_matches occurs at h near N/2:
        // delta = spacing * (N_try - 2*(N_try/2) - spacing) * (1-2*eps)... simplified:
        // Actually the edge count difference between h and h+spacing:
        // edges(h+s) - edges(h) = s*(2*N_try - 2*h - s - 1)/2
        // Minimum at h = (N_try - s - 1)/2, giving diff = s*(N_try - s)/2 ≈ s*N_try/2 for s<<N
        // After noise scaling: expected_edges_diff * (1-2*eps) = s * N_try/2 * (1-2*eps)
        // Noise std of total edge count = sqrt(L_try * eps * (1-eps))
        double min_edge_diff = spacing * N_try / 2.0 * std::max(0.01, 1.0 - 2.0 * eps);
        double noise_std = std::sqrt(L_try * eps * (1.0 - eps));
        double snr = min_edge_diff / noise_std;

        // P(error) ≈ erfc(snr / sqrt(2)) but capped
        double p_err;
        if (snr > 5.0) p_err = 0.0;
        else if (snr > 0.0) p_err = 0.5 * std::erfc(snr / std::sqrt(2.0));
        else p_err = 0.5;

        double obj = 10.536 * 100.0 * p_err + std::log((double)N_try);
        if (obj < best_obj) {
            best_obj = obj;
            best_N_try = N_try;
        }
    }
    N_ACTUAL = best_N_try;
}

