} else {
    // Threshold graph approach
    // Choose hub counts to give evenly-spaced EDGE COUNTS rather than evenly-spaced hub counts.
    // Edge count for h hubs: E(h) = h*(2N-h-1)/2
    // This is concave in h, so evenly spaced h gives uneven edge spacing (sparser at extremes).
    // Instead, find h values that give E(h) ≈ k * L / (M-1) for k=0..M-1.
    hub_counts.resize(M_graphs);
    if (M_graphs == 1) {
        hub_counts[0] = N_ACTUAL / 2;
    } else {
        // Target edge counts: evenly spaced from 0 to L
        for (int k = 0; k < M_graphs; ++k) {
            double target_edges = (double)k * L_ACTUAL / (M_graphs - 1);
            // Solve h*(2N-h-1)/2 = target_edges for h
            // h^2 - (2N-1)*h + 2*target_edges = 0
            // h = ((2N-1) - sqrt((2N-1)^2 - 8*target_edges)) / 2
            double disc = (2.0*N_ACTUAL - 1.0)*(2.0*N_ACTUAL - 1.0) - 8.0*target_edges;
            int h;
            if (disc < 0) {
                h = N_ACTUAL - 1;
            } else {
                h = (int)std::round(((2.0*N_ACTUAL - 1.0) - std::sqrt(disc)) / 2.0);
            }
            h = std::max(0, std::min(N_ACTUAL - 1, h));
            hub_counts[k] = h;
        }
        // Ensure strictly increasing
        for (int k = 1; k < M_graphs; ++k) {
            if (hub_counts[k] <= hub_counts[k - 1]) {
                hub_counts[k] = hub_counts[k - 1] + 1;
            }
